def get_ludic(limit):
    ludics = [True] * (limit + 1)
    p = 2
    while (p * p <= limit):
        if (ludics[p] == True):
            i = p * p
            while (i <= limit):
                ludics[i] = False
                i += p
        p += 1
    ludic_numbers = []
    for i in range(2, limit + 1):
        if (ludics[i] == True):
            ludic_numbers.append(i)
    return ludic_numbers

