from functools import lru_cache

def largest_subset(nums):
    @lru_cache(None)
    def dp(i, last):
        if i >= len(nums):
            return 0
        if nums[i] % last == 0:
            return 1 + dp(i+1, nums[i])
        else:
            return dp(i+1, last)
    return max(dp(i, -1) for i in range(len(nums)))

