import re

def occurance_substring(main_str, sub_str):
    # Using regular expression to find all occurrences of the substring
    matches = re.finditer(r'\b' + re.escape(sub_str) + r'\b', main_str)
    for match in matches:
        start = match.start()
        end = match.end()
        return (sub_str, start, end)
    return None

